<span class="line"><span style="color:#CDD6F4;">            index</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> HashMap</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(),</span></span>
